ValidationRule.errorConditionFormula:
AND( ISPICKVAL(Translation_Request_Type__c, 'Translation and Publication') ,  
     OR(Translation_Due_Date__c >  DueDate__c,
        AND (ISCHANGED(DueDate__c), DATEVALUE(DueDate__c) = TODAY()),
        AND(ISCHANGED(Translation_Due_Date__c),	DATEVALUE(Translation_Due_Date__c) = TODAY())
					)
)
